ALLOWED_FILES = {"file1.txt", "file2.txt"}

@app.route("/download")
def download():
    filename = request.args.get("file", "")
    file_path = os.path.abspath(os.path.join(BASE_DIR, filename))
    if not file_path.startswith(BASE_DIR):
        abort(403)
